+/// Truncates a string for display in error messages.
+fn truncate_for_display(s: &str, max_len: usize) -> &str {
+    if s.len() <= max_len {
+        s
+    } else {
+        // Find a safe truncation point (don't split UTF-8)
+        let truncate_at = s
+            .char_indices()
+            .take_while(|(i, _)| *i < max_len - 3)
+            .last()
+            .map(|(i, c)| i + c.len_utf8())
+            .unwrap_or(max_len - 3);
+        &s[..truncate_at]
+    }
+}
